input.onclick:
                                const cbs = document.querySelectorAll('.pick_cb');
                                cbs.forEach(cb => {
    cb.checked = this.checked;
    cb.dispatchEvent(new Event('change'));
});

input.onchange:
const box = this;
const cont = document.getElementById('selected_pickings_container');
if (box.checked) {
    const i = document.createElement('input');
    i.type = 'hidden';
    i.name = 'picking_ids[]';
    i.value = box.value;
    i.id = 'hid_' + box.value;
    cont.appendChild(i);
} else {
    const i = document.getElementById('hid_' + box.value);
    if (i) i.remove();
}
